// This is a Prisma schema file.
// Learn more: https://pris.ly/d/prisma-schema

datasource db {
  provider = "sqlite"
}

generator client {
  provider = "prisma-client-js"
}

model Bead {
  id        Int      @id @default(autoincrement())
  name      String
  nameRu    String
  shape     String   // "sphere" | "disc" | "star" | "heart" | "cylinder" — mapped in app
  size      Float
  material  String   // "wood" | "silicone" | "knit" | "plastic" — mapped in app
  color     String
  createdAt DateTime @default(now())
}

model Template {
  id              Int      @id @default(autoincrement())
  name            String
  designCode      String   @unique
  beadCount       Int
  isApproved      Boolean  @default(true)
  isUserSubmitted Boolean  @default(false)
  createdAt       DateTime @default(now())
}

model Order {
  id          Int      @id @default(autoincrement())
  designCode  String   @unique
  designState String   // JSON string of SerializableDesign
  status      String   @default("new")  // "new" | "processing" | "completed"
  beadCount   Int
  createdAt   DateTime @default(now())
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function GET() {
  const templates = await prisma.template.findMany({
    where: { isApproved: true },
    orderBy: { createdAt: "desc" },
  });

  return NextResponse.json(templates);
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { designCode, beadCount } = body;

    if (!designCode || !beadCount) {
      return NextResponse.json(
        { error: "designCode and beadCount are required" },
        { status: 400 }
      );
    }

    const order = await prisma.order.create({
      data: {
        designCode,
        designState: JSON.stringify({ designCode, beadCount }),
        status: "new",
        beadCount: Number(beadCount),
      },
    });

    return NextResponse.json(order, { status: 201 });
  } catch (error) {
    console.error("Failed to create order:", error);
    return NextResponse.json(
      { error: "Failed to create order" },
      { status: 500 }
    );
  }
}

export async function GET() {
  try {
    const orders = await prisma.order.findMany({
      orderBy: { createdAt: "desc" },
    });

    return NextResponse.json(orders);
  } catch (error) {
    console.error("Failed to fetch orders:", error);
    return NextResponse.json(
      { error: "Failed to fetch orders" },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

export async function GET(
  _req: Request,
  { params }: { params: Promise<{ code: string }> }
) {
  const { code } = await params;

  const template = await prisma.template.findUnique({
    where: { designCode: code },
  });

  if (!template) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  return NextResponse.json(template);
}

