/**
 * Seed script for Prisma — populates the Template table with 8 pre-made designs.
 *
 * Usage: npx prisma db seed
 *
 * This script uses real catalog bead IDs to generate design codes via encodeDesign,
 * producing valid round-trippable codes that the frontend can decode and load.
 */

import "dotenv/config";
import { PrismaClient } from "@prisma/client";
import { PrismaLibSql } from "@prisma/adapter-libsql";
import { CATALOG_BEADS, getCatalogBead } from "../src/data/catalogBeads";
import { catalogBeadToBeadState } from "../src/lib/catalogUtils";
import { encodeDesign } from "../src/lib/serialization";

const adapter = new PrismaLibSql({ url: process.env.DATABASE_URL! });
const prisma = new PrismaClient({ adapter });

/**
 * Each template definition: name, and the catalog bead IDs that make up the design.
 * Using real IDs from the catalog spanning different materials for variety.
 */
const templates: { name: string; beads: string[] }[] = [
  {
    name: "Розовая классика",
    beads: [
      "cb-026", "cb-032", "cb-036", "cb-026", "cb-042", "cb-032",
      "cb-036", "cb-026", "cb-045", "cb-032", "cb-026", "cb-036",
    ],
  },
  {
    name: "Натуральное дерево",
    beads: [
      "cb-001", "cb-003", "cb-005", "cb-001", "cb-003", "cb-009",
      "cb-001", "cb-003", "cb-005", "cb-012", "cb-001", "cb-003",
    ],
  },
  {
    name: "Весенняя свежесть",
    beads: [
      "cb-028", "cb-034", "cb-027", "cb-028", "cb-053", "cb-028",
      "cb-034", "cb-043", "cb-028", "cb-034", "cb-027", "cb-028",
    ],
  },
  {
    name: "Яркий микс",
    beads: [
      "cb-076", "cb-078", "cb-077", "cb-079", "cb-080", "cb-076",
      "cb-078", "cb-077", "cb-079", "cb-080", "cb-076", "cb-078",
    ],
  },
  {
    name: "Лавандовый сон",
    beads: [
      "cb-029", "cb-041", "cb-035", "cb-029", "cb-050", "cb-029",
      "cb-041", "cb-035", "cb-029", "cb-050", "cb-029", "cb-041",
    ],
  },
  {
    name: "Тёплый уют",
    beads: [
      "cb-051", "cb-052", "cb-055", "cb-051", "cb-069", "cb-051",
      "cb-052", "cb-055", "cb-059", "cb-051", "cb-052", "cb-055",
    ],
  },
  {
    name: "Морской бриз",
    beads: [
      "cb-027", "cb-046", "cb-086", "cb-027", "cb-046", "cb-033",
      "cb-027", "cb-046", "cb-086", "cb-027", "cb-033", "cb-046",
    ],
  },
  {
    name: "Лесная сказка",
    beads: [
      "cb-002", "cb-004", "cb-010", "cb-057", "cb-002", "cb-004",
      "cb-057", "cb-011", "cb-002", "cb-004", "cb-010", "cb-057",
    ],
  },
];

async function main() {
  console.log("Seeding templates...");

  // Validate all bead IDs before inserting
  for (const tmpl of templates) {
    const invalid = tmpl.beads.filter((id) => !getCatalogBead(id));
    if (invalid.length > 0) {
      throw new Error(
        `Template "${tmpl.name}" has invalid bead IDs: ${invalid.join(", ")}`
      );
    }
  }

  // Clear existing templates for idempotent seeding
  await prisma.template.deleteMany();
  console.log("  Cleared existing templates.");

  for (const tmpl of templates) {
    // Convert catalog IDs → BeadState[] → design code
    const beadStates = tmpl.beads
      .map((id) => {
        const catalogBead = getCatalogBead(id)!;
        return catalogBeadToBeadState(catalogBead);
      });

    const designCode = encodeDesign(beadStates);

    await prisma.template.create({
      data: {
        name: tmpl.name,
        designCode,
        beadCount: tmpl.beads.length,
      },
    });

    console.log(`  ✓ ${tmpl.name} (${tmpl.beads.length} beads)`);
  }

  const count = await prisma.template.count();
  console.log(`\nDone! ${count} templates seeded.`);
}

main()
  .catch((e) => {
    console.error("Seed failed:", e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

import LZString from "lz-string";
import type { BeadState, SerializableDesign } from "@/types/bead";

/**
 * Encode an array of BeadState objects into a URL-safe design code.
 *
 * Pipeline: filter beads with catalogBeadId → JSON.stringify → LZ-String compress → base64url.
 * Only beads that have a `catalogBeadId` are included; others are silently skipped.
 */
export function encodeDesign(beads: BeadState[]): string {
  const catalogIds = beads
    .filter((b) => b.catalogBeadId)
    .map((b) => b.catalogBeadId as string);

  const design: SerializableDesign = {
    v: 1,
    p: "pacifier-holder",
    b: catalogIds,
  };

  return LZString.compressToEncodedURIComponent(JSON.stringify(design));
}

/**
 * Decode a URL-safe design code back into a SerializableDesign.
 *
 * Applies `decodeURIComponent` first because lz-string output may contain
 * `+` which browsers encode as `%2B` in URL path segments, and Next.js
 * does not decode `%2B` back to `+` in dynamic route params.
 *
 * Returns `null` for any invalid input: malformed base64url, invalid JSON,
 * missing required fields, or unsupported version.
 */
export function decodeDesign(code: string): SerializableDesign | null {
  if (!code || typeof code !== "string") return null;

  try {
    // Normalize URL-encoded characters (e.g. %2B → +) that may appear
    // when design codes are embedded in URL path segments.
    const normalized = decodeURIComponent(code);

    const json = LZString.decompressFromEncodedURIComponent(normalized);
    if (!json) return null;

    const parsed: unknown = JSON.parse(json);

    const obj = parsed as Record<string, unknown>;
    if (obj.v !== 1 || typeof obj.p !== "string" || !Array.isArray(obj.b)) {
      return null;
    }
    if (!(obj.b as unknown[]).every((id) => typeof id === "string")) {
      return null;
    }

    return parsed as SerializableDesign;
  } catch {
    return null;
  }
}

import type { CatalogBead, BeadState } from "@/types/bead";

/**
 * Convert a catalog bead definition into a runtime BeadState
 * suitable for the 3D physics chain.
 *
 * Mapping rules:
 * - id:          unique instance id (timestamp + random suffix)
 * - catalogBeadId: preserved for round-trip back to catalog
 * - type:        material maps directly to BeadType
 * - radius:      catalog `size` is a diameter-like concept; radius = size × 0.8
 * - color:       carried through as-is
 */
export function catalogBeadToBeadState(catalogBead: CatalogBead): BeadState {
  return {
    id: `bead-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    catalogBeadId: catalogBead.id,
    type: catalogBead.material,
    radius: catalogBead.size * 0.8,
    color: catalogBead.color,
  };
}

export type BeadId = string;
export type BeadType = "wood" | "silicone" | "knit" | "plastic";
export type BeadShape = "sphere" | "disc" | "star" | "heart" | "cylinder";

export interface CatalogBead {
  id: string;
  name: string;
  nameRu: string;
  shape: BeadShape;
  size: number;
  material: BeadType;
  color: string;
  secondaryColor?: string;
}

export interface BeadState {
  id: BeadId;
  type: BeadType;
  radius: number;
  color: string;
  catalogBeadId?: string;
}

export interface ChainConfig {
  anchorPosition: [number, number, number];
  gravity: [number, number, number];
}

export interface ChainState {
  beads: BeadState[];
  config: ChainConfig;
}

/** Wire format for design serialization (JSON → LZ-String → base64url). */
export interface SerializableDesign {
  v: 1;
  p: "pacifier-holder";
  b: string[]; // catalogBeadId strings
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { useDesignStore } from "@/stores/useDesignStore";
import { encodeDesign } from "@/lib/serialization";
import { generateTelegramLink } from "@/lib/telegram";

interface EditorToolbarProps {
  catalogOpen: boolean;
  onToggleCatalog: () => void;
}

/**
 * Fixed bottom toolbar with glass-morphism styling.
 * Reads bead count and selection state from the design store.
 * Provides four action buttons: catalog toggle, remove selected, share, reset.
 */
export function EditorToolbar({ catalogOpen, onToggleCatalog }: EditorToolbarProps) {
  const beadCount = useDesignStore((s) => s.beads.length);
  const selectedId = useDesignStore((s) => s.selectedBeadId);
  const beads = useDesignStore((s) => s.beads);

  // ── Share state ────────────────────────────────────────────────
  const [copied, setCopied] = useState(false);
  const [isOrdering, setIsOrdering] = useState(false);
  const [orderError, setOrderError] = useState<string | null>(null);

  useEffect(() => {
    if (!copied) return;
    const timer = setTimeout(() => setCopied(false), 2000);
    return () => clearTimeout(timer);
  }, [copied]);

  useEffect(() => {
    if (!orderError) return;
    const timer = setTimeout(() => setOrderError(null), 3000);
    return () => clearTimeout(timer);
  }, [orderError]);

  const canShare = beads.some((b) => !!b.catalogBeadId);

  const handleShare = useCallback(async () => {
    if (!canShare) return;
    try {
      const code = encodeDesign(beads);
      if (!code) return;
      const url = `${window.location.origin}/design/${code}`;
      await navigator.clipboard.writeText(url);
      setCopied(true);
    } catch (err) {
      console.error("Failed to copy share URL:", err);
    }
  }, [beads, canShare]);

  const canOrder = beads.length > 0;

  const handleOrder = useCallback(async () => {
    if (!canOrder || isOrdering) return;
    setIsOrdering(true);
    setOrderError(null);
    try {
      const code = encodeDesign(beads);
      if (!code) return;
      const res = await fetch("/api/orders", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ designCode: code, beadCount: beads.length }),
      });
      if (!res.ok) throw new Error("Order failed");
      const order = await res.json();
      const link = generateTelegramLink(order.designCode, order.beadCount);
      window.open(link, "_blank", "noopener");
    } catch (err) {
      console.error("Failed to create order:", err);
      setOrderError("Не удалось создать заказ");
    } finally {
      setIsOrdering(false);
    }
  }, [beads, canOrder, isOrdering]);

  return (
    <div
      className="fixed bottom-0 left-0 right-0 flex flex-col gap-2 px-4 py-3 bg-white/70 backdrop-blur-md border-t border-gray-200/50 z-10"
      style={{ touchAction: "manipulation" }}
    >
      {/* ── Order CTA (full-width above actions) ──────────────── */}
      <button
        onClick={handleOrder}
        disabled={!canOrder || isOrdering}
        className="w-full py-2.5 text-sm font-semibold rounded-xl text-white transition-all duration-150 disabled:opacity-30 disabled:cursor-not-allowed cursor-pointer select-none active:scale-[0.98]"
        style={{ backgroundColor: isOrdering ? "#9ca3af" : "#10b981" }}
      >
        {isOrdering ? "Отправка..." : orderError ? orderError : "🛒 Заказать"}
      </button>

      {/* ── Bottom row: bead count + action buttons ──────────── */}
      <div className="flex items-center justify-between">
        {/* ── Left: bead count badge ────────────────────────────── */}
        <span className="text-sm font-medium text-gray-600 tabular-nums select-none">
          {beadCount}{" "}
          {beadCount === 1 ? "бусина" : beadCount < 5 ? "бусины" : "бусин"}
        </span>

        {/* ── Right: action buttons ─────────────────────────────── */}
        <div className="flex items-center gap-2">
          {/* Catalog toggle */}
          <button
            onClick={onToggleCatalog}
            className="inline-flex items-center gap-1.5 px-3.5 py-2 text-sm font-medium rounded-xl transition-all duration-150 cursor-pointer select-none active:scale-95"
            style={{
              backgroundColor: catalogOpen ? "#dbeafe" : "#f0fdf4",
              color: catalogOpen ? "#1d4ed8" : "#15803d",
            }}
            aria-label={catalogOpen ? "Закрыть каталог" : "Открыть каталог"}
            aria-expanded={catalogOpen}
          >
            <CatalogIcon open={catalogOpen} />
            <span>{catalogOpen ? "Закрыть" : "Каталог"}</span>
          </button>

          {/* Remove selected bead */}
          <button
            onClick={() => useDesignStore.getState().removeSelected()}
            disabled={!selectedId}
            className="inline-flex items-center gap-1.5 px-3 py-2 text-sm font-medium rounded-xl bg-rose-50 text-rose-700 hover:bg-rose-100 transition-all duration-150 disabled:opacity-30 disabled:cursor-not-allowed cursor-pointer select-none active:scale-95"
            aria-label="Удалить выбранную бусину"
          >
            <TrashIcon />
            <span>Удалить</span>
          </button>

          {/* Share / Поделиться */}
          <button
            onClick={handleShare}
            disabled={!canShare}
            className="inline-flex items-center gap-1.5 px-3 py-2 text-sm font-medium rounded-xl bg-blue-50 text-blue-700 hover:bg-blue-100 transition-all duration-150 disabled:opacity-30 disabled:cursor-not-allowed cursor-pointer select-none active:scale-95"
            aria-label="Поделиться ссылкой на дизайн"
          >
            {copied ? <CheckIcon /> : <ShareIcon />}
            <span>{copied ? "Скопировано!" : "Поделиться"}</span>
          </button>

          {/* Reset design */}
          <button
            onClick={() => useDesignStore.getState().resetDesign()}
            className="inline-flex items-center gap-1.5 px-3 py-2 text-sm font-medium rounded-xl bg-gray-100 text-gray-600 hover:bg-gray-200 transition-all duration-150 cursor-pointer select-none active:scale-95"
            aria-label="Сбросить цепочку"
          >
            <ResetIcon />
            <span>Сброс</span>
          </button>
        </div>
      </div>
    </div>
  );
}

